conv2d_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <vector>

#define TILE_SIZE 16
#define BLOCK_SIZE 256

template<typename scalar_t>
__global__ void conv2d_forward_kernel(
    const scalar_t* input,
    const scalar_t* weight,
    const scalar_t* bias,
    scalar_t* output,
    int batch_size,
    int in_channels,
    int out_channels,
    int input_height,
    int input_width,
    int kernel_height,
    int kernel_width,
    int stride_height,
    int stride_width,
    int padding_height,
    int padding_width,
    int dilation_height,
    int dilation_width,
    int output_height,
    int output_width) {

    // Shared memory for tile of input and weight
    __shared__ scalar_t input_tile[TILE_SIZE][TILE_SIZE];
    __shared__ scalar_t weight_tile[TILE_SIZE][TILE_SIZE];

    int output_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (output_idx >= batch_size * out_channels * output_height * output_width) {
        return;
    }

    // Decompose output index
    int n = output_idx / (out_channels * output_height * output_width);
    int oc = (output_idx / (output_height * output_width)) % out_channels;
    int oh = (output_idx / output_width) % output_height;
    int ow = output_idx % output_width;

    scalar_t result = 0.0;

    // Loop over input channels
    for (int ic = 0; ic < in_channels; ic++) {
        // Loop over kernel height
        for (int kh = 0; kh < kernel_height; kh++) {
            int ih = oh * stride_height + kh * dilation_height - padding_height;
            if (ih < 0 || ih >= input_height) continue;

            // Loop over kernel width
            for (int kw = 0; kw < kernel_width; kw++) {
                int iw = ow * stride_width + kw * dilation_width - padding_width;
                if (iw < 0 || iw >= input_width) continue;

                // Input index calculation
                int input_idx = ((n * in_channels + ic) * input_height + ih) * input_width + iw;

                // Weight index calculation
                int weight_idx = ((oc * in_channels + ic) * kernel_height + kh) * kernel_width + kw;

                result += input[input_idx] * weight[weight_idx];
            }
        }
    }

    // Add bias if present
    if (bias != nullptr) {
        result += bias[oc];
    }

    // Store result
    output[output_idx] = result;
}

torch::Tensor conv2d_forward_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    int stride_height,
    int stride_width,
    int padding_height,
    int padding_width,
    int dilation_height,
    int dilation_width) {

    // Get tensor dimensions
    int batch_size = input.size(0);
    int in_channels = input.size(1);
    int input_height = input.size(2);
    int input_width = input.size(3);
    int out_channels = weight.size(0);
    int kernel_height = weight.size(2);
    int kernel_width = weight.size(3);

    // Calculate output dimensions
    int output_height = (input_height - 2 * padding_height - dilation_height * (kernel_height - 1) - 1) / stride_height + 1;
    int output_width = (input_width + 2 * padding_width - dilation_width * (kernel_width - 1) - 1) / stride_width + 1;

    // Create output tensor
    auto output = torch::zeros({batch_size, out_channels, output_height, output_width}, 
                              input.options());

    // Calculate total number of output elements
    int total_output_elements = batch_size * out_channels * output_height * output_width;

    // Configure kernel launch parameters
    const int block_size = BLOCK_SIZE;
    const int num_blocks = (total_output_elements + block_size - 1) / block_size;

    // Launch kernel based on data type
    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "conv2d_forward_cuda", ([&] {
        const scalar_t* input_ptr = input.data_ptr<scalar_t>();
        const scalar_t* weight_ptr = weight.data_ptr<scalar_t>();
        const scalar_t* bias_ptr = bias.defined() ? bias.data_ptr<scalar_t>() : nullptr;
